import{_ as e,c as s,o as t,ae as i}from"./chunks/framework.CDjunVez.js";const u=JSON.parse('{"title":"Updating KiwiPanel","description":"","frontmatter":{},"headers":[],"relativePath":"features/update.md","filePath":"features/update.md"}'),n={name:"features/update.md"};function l(p,a,r,o,d,h){return t(),s("div",null,[...a[0]||(a[0]=[i(`<h1 id="updating-kiwipanel" tabindex="-1">Updating KiwiPanel <a class="header-anchor" href="#updating-kiwipanel" aria-label="Permalink to &quot;Updating KiwiPanel&quot;">​</a></h1><p>KiwiPanel does <strong>not</strong> update automatically. You must explicitly check for new versions and choose when to apply updates. The update system is designed for zero-downtime — the page automatically reloads once the new version is running.</p><h2 id="checking-for-updates" tabindex="-1">Checking for Updates <a class="header-anchor" href="#checking-for-updates" aria-label="Permalink to &quot;Checking for Updates&quot;">​</a></h2><h3 id="from-the-dashboard" tabindex="-1">From the Dashboard <a class="header-anchor" href="#from-the-dashboard" aria-label="Permalink to &quot;From the Dashboard&quot;">​</a></h3><ol><li>Navigate to <strong>System → Update</strong> (or go to <code>https://your-server:8443/dashboard/update</code>)</li><li>The page automatically checks for the latest version on load</li><li>You&#39;ll see one of two states:</li></ol><p><strong>System is up to date:</strong></p><blockquote><p>✅ System is up to date<br> Current version: 0.7.0 (latest: 0.7.0)</p></blockquote><p><strong>Update available:</strong></p><blockquote><p>ℹ️ Update available: 0.8.0<br> Current: 0.7.0 → Latest: 0.8.0</p></blockquote><p>You can also click the <strong>Check for Updates</strong> button at any time to re-check.</p><h3 id="from-the-cli" tabindex="-1">From the CLI <a class="header-anchor" href="#from-the-cli" aria-label="Permalink to &quot;From the CLI&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kiwipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> panel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div><p>This checks GitHub for the latest release and compares it against your installed version using semver.</p><h2 id="applying-an-update" tabindex="-1">Applying an Update <a class="header-anchor" href="#applying-an-update" aria-label="Permalink to &quot;Applying an Update&quot;">​</a></h2><p>When an update is available, the <strong>Apply Update</strong> button appears. The entire process is automated:</p><ol><li>Click <strong>Apply Update</strong> and confirm the prompt</li><li>The update runs in the background — you can watch progress in real-time via the status log</li><li>When the service restarts, a &quot;Service is restarting&quot; overlay appears automatically</li><li>Once the service is back online, the page reloads itself</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You do not need to stay on the page. The update continues in the background even if you close the browser. You can return to the update page later to see the result.</p></div><h3 id="what-happens-behind-the-scenes" tabindex="-1">What Happens Behind the Scenes <a class="header-anchor" href="#what-happens-behind-the-scenes" aria-label="Permalink to &quot;What Happens Behind the Scenes&quot;">​</a></h3><p>The update follows a strict pipeline:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Apply Update clicked</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ 1. Cleanup any previous failed update</span></span>
<span class="line"><span>    ├─ 2. Fetch latest release from GitHub</span></span>
<span class="line"><span>    ├─ 3. Match binary for your OS/architecture</span></span>
<span class="line"><span>    ├─ 4. Download panel binary + SHA-256 verify</span></span>
<span class="line"><span>    ├─ 5. Download agent binary + SHA-256 verify</span></span>
<span class="line"><span>    ├─ 6. Write staging metadata (staged.json)</span></span>
<span class="line"><span>    ├─ 7. Create staged flag file</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ systemd detects the flag automatically:</span></span>
<span class="line"><span>    │      kiwipanel-update.path → triggers kiwipanel-update.service</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └─ Update apply (runs as root):</span></span>
<span class="line"><span>           1. Validate binary (ELF magic bytes)</span></span>
<span class="line"><span>           2. Verify SHA-256 checksum</span></span>
<span class="line"><span>           3. Stop kiwipanel.service</span></span>
<span class="line"><span>           4. Backup current binary → .bak</span></span>
<span class="line"><span>           5. Install new binary</span></span>
<span class="line"><span>           6. Start kiwipanel.service</span></span>
<span class="line"><span>           7. Health check (systemctl + TCP port 8443)</span></span>
<span class="line"><span>           8. Apply agent update (if available)</span></span>
<span class="line"><span>           9. Update version metadata</span></span>
<span class="line"><span>          10. Write status &quot;done&quot;</span></span></code></pre></div><h3 id="status-states" tabindex="-1">Status States <a class="header-anchor" href="#status-states" aria-label="Permalink to &quot;Status States&quot;">​</a></h3><p>The update page shows real-time progress via Server-Sent Events (SSE):</p><table tabindex="0"><thead><tr><th>State</th><th>What&#39;s happening</th></tr></thead><tbody><tr><td><strong>Checking</strong></td><td>Querying GitHub for the latest version</td></tr><tr><td><strong>Available</strong></td><td>New version found, waiting for you to apply</td></tr><tr><td><strong>Downloading</strong></td><td>Downloading binaries from GitHub</td></tr><tr><td><strong>Validating</strong></td><td>Checking binary format (ELF)</td></tr><tr><td><strong>Verifying</strong></td><td>Verifying SHA-256 checksums</td></tr><tr><td><strong>Installing</strong></td><td>Replacing binaries + restarting the service</td></tr><tr><td><strong>Finalizing</strong></td><td>Updating version metadata and cleanup</td></tr><tr><td><strong>Ready</strong></td><td>Staged and waiting for systemd to apply</td></tr><tr><td><strong>Done</strong></td><td>Update complete ✅</td></tr><tr><td><strong>Error</strong></td><td>Something failed — click Retry</td></tr></tbody></table><h2 id="automatic-rollback" tabindex="-1">Automatic Rollback <a class="header-anchor" href="#automatic-rollback" aria-label="Permalink to &quot;Automatic Rollback&quot;">​</a></h2><p>If anything goes wrong during the update, KiwiPanel automatically rolls back:</p><ul><li><strong>Service fails to start</strong> → previous binary is restored, service restarted</li><li><strong>Health check fails</strong> (service not responding on port 8443 within 30s) → rollback triggered</li><li><strong>Checksum mismatch</strong> → update aborted before any binary replacement</li></ul><p>The previous binary is always preserved as a <code>.bak</code> file until the update succeeds.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Rollback restores the previous version automatically. If you see an error state, click <strong>Retry</strong> to attempt the update again, or check the update logs for details.</p></div><h2 id="service-restart-detection" tabindex="-1">Service Restart Detection <a class="header-anchor" href="#service-restart-detection" aria-label="Permalink to &quot;Service Restart Detection&quot;">​</a></h2><p>When the service restarts during an update, the browser loses its SSE connection. KiwiPanel handles this gracefully:</p><ol><li>A <strong>&quot;Service is restarting&quot;</strong> overlay appears with a countdown timer</li><li>The page polls the <code>/ping</code> endpoint every 3 seconds</li><li>Once the service responds, it shows &quot;Service is back!&quot; and reloads the page automatically</li></ol><p>The <code>/ping</code> endpoint is unauthenticated and lightweight — it works even when sessions are cleared by the restart.</p><h2 id="security-model" tabindex="-1">Security Model <a class="header-anchor" href="#security-model" aria-label="Permalink to &quot;Security Model&quot;">​</a></h2><h3 id="privilege-separation" tabindex="-1">Privilege Separation <a class="header-anchor" href="#privilege-separation" aria-label="Permalink to &quot;Privilege Separation&quot;">​</a></h3><p>The update process uses strict privilege separation:</p><table tabindex="0"><thead><tr><th>Component</th><th>Runs as</th><th>What it does</th></tr></thead><tbody><tr><td>Web panel</td><td><code>kiwipanel:kiwisecure</code></td><td>Downloads, verifies, stages binaries</td></tr><tr><td>Update apply</td><td><code>root</code> (via systemd)</td><td>Replaces binaries, restarts services</td></tr></tbody></table><p>The web panel <strong>never</strong> runs as root. Binary replacement and service control are delegated to a systemd oneshot service.</p><h3 id="integrity-verification" tabindex="-1">Integrity Verification <a class="header-anchor" href="#integrity-verification" aria-label="Permalink to &quot;Integrity Verification&quot;">​</a></h3><p>Every downloaded binary goes through:</p><ol><li><strong>SHA-256 checksum</strong> — computed during download and compared against the release manifest</li><li><strong>ELF validation</strong> — binary must contain valid ELF magic bytes (<code>0x7F &#39;E&#39; &#39;L&#39; &#39;F&#39;</code>)</li><li><strong>Atomic staging</strong> — binaries are downloaded to <code>.tmp</code>, verified, then renamed (no partial writes)</li></ol><h3 id="concurrency-protection" tabindex="-1">Concurrency Protection <a class="header-anchor" href="#concurrency-protection" aria-label="Permalink to &quot;Concurrency Protection&quot;">​</a></h3><p>A file lock (<code>apply.lock</code>) prevents multiple updates from running simultaneously. If an update is already in progress, additional attempts fail immediately.</p><h2 id="filesystem-layout" tabindex="-1">Filesystem Layout <a class="header-anchor" href="#filesystem-layout" aria-label="Permalink to &quot;Filesystem Layout&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/var/lib/kiwipanel/update/</span></span>
<span class="line"><span>├── status.json          # Current update status (read by SSE)</span></span>
<span class="line"><span>├── staged               # Flag file — triggers systemd path unit</span></span>
<span class="line"><span>├── staged.json          # Metadata: version, URLs, checksums</span></span>
<span class="line"><span>├── kiwipanel.new        # Staged panel binary</span></span>
<span class="line"><span>├── kiwipanel-agent.new  # Staged agent binary (if available)</span></span>
<span class="line"><span>└── apply.lock           # Prevents concurrent updates</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/opt/kiwipanel/bin/</span></span>
<span class="line"><span>├── kiwipanel            # Active panel binary</span></span>
<span class="line"><span>├── kiwipanel.bak        # Previous version (rollback target)</span></span>
<span class="line"><span>├── kiwipanel-agent      # Active agent binary</span></span>
<span class="line"><span>└── kiwipanel-agent.bak  # Previous agent version</span></span>
<span class="line"><span></span></span>
<span class="line"><span>/opt/kiwipanel/meta/</span></span>
<span class="line"><span>└── current.version      # Version metadata</span></span></code></pre></div><h2 id="systemd-units" tabindex="-1">systemd Units <a class="header-anchor" href="#systemd-units" aria-label="Permalink to &quot;systemd Units&quot;">​</a></h2><p>The update is triggered automatically by a systemd path unit:</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-YTLCg" id="tab-xB97pQ3" checked><label data-title="kiwipanel-update.path" for="tab-xB97pQ3">kiwipanel-update.path</label><input type="radio" name="group-YTLCg" id="tab-Lcggn1M"><label data-title="kiwipanel-update.service" for="tab-Lcggn1M">kiwipanel-update.service</label></div><div class="blocks"><div class="language-ini vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Unit]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=Watch for KiwiPanel staged updates</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Path]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">PathModified</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/var/lib/kiwipanel/update/staged</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Unit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=kiwipanel-update.service</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TriggerLimitIntervalSec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=30</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TriggerLimitBurst</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=3</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Install]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WantedBy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=multi-user.target</span></span></code></pre></div><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Unit]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=KiwiPanel Apply Staged Update</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">After</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=network.target</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Service]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Type</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=oneshot</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ExecStart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/opt/kiwipanel/bin/kiwipanel panel update apply</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">User</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=root</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Group</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=root</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TimeoutStartSec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=300</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Install]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WantedBy</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=multi-user.target</span></span></code></pre></div></div></div><p>When <code>PrepareUpdate()</code> creates the <code>/var/lib/kiwipanel/update/staged</code> flag file, the path unit detects it and triggers the update service, which runs <code>kiwipanel panel update apply</code> as root.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="update-stuck-on-checking" tabindex="-1">Update stuck on &quot;Checking...&quot; <a class="header-anchor" href="#update-stuck-on-checking" aria-label="Permalink to &quot;Update stuck on &quot;Checking...&quot;&quot;">​</a></h3><p>The version check has a 10-second timeout. If your server can&#39;t reach GitHub&#39;s API (<code>api.github.com</code>), the check will fail. Verify:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://api.github.com/repos/kiwipanel/kiwipanel/releases/latest</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -5</span></span></code></pre></div><h3 id="update-failed-with-no-binary-found-for-linux-amd64" tabindex="-1">Update failed with &quot;No binary found for linux/amd64&quot; <a class="header-anchor" href="#update-failed-with-no-binary-found-for-linux-amd64" aria-label="Permalink to &quot;Update failed with &quot;No binary found for linux/amd64&quot;&quot;">​</a></h3><p>The release doesn&#39;t include a binary for your platform. Check that the release has an asset named <code>kiwipanel-linux-amd64</code> (or your OS/arch combination).</p><h3 id="another-update-is-already-running" tabindex="-1">&quot;Another update is already running&quot; <a class="header-anchor" href="#another-update-is-already-running" aria-label="Permalink to &quot;&quot;Another update is already running&quot;&quot;">​</a></h3><p>An update lock file exists. Wait for the current update to finish, or if it&#39;s stuck:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/lib/kiwipanel/update/apply.lock</span></span></code></pre></div><h3 id="service-didn-t-restart-after-staging" tabindex="-1">Service didn&#39;t restart after staging <a class="header-anchor" href="#service-didn-t-restart-after-staging" aria-label="Permalink to &quot;Service didn&#39;t restart after staging&quot;">​</a></h3><p>Check if the systemd path unit is active:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kiwipanel-update.path</span></span></code></pre></div><p>If it&#39;s not running:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --now</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kiwipanel-update.path</span></span></code></pre></div><h3 id="manual-rollback" tabindex="-1">Manual rollback <a class="header-anchor" href="#manual-rollback" aria-label="Permalink to &quot;Manual rollback&quot;">​</a></h3><p>If you need to manually restore the previous version:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stop</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kiwipanel.service</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /opt/kiwipanel/bin/kiwipanel.bak</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /opt/kiwipanel/bin/kiwipanel</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kiwipanel.service</span></span></code></pre></div><h3 id="view-update-logs" tabindex="-1">View update logs <a class="header-anchor" href="#view-update-logs" aria-label="Permalink to &quot;View update logs&quot;">​</a></h3><p>Update events are logged to <code>/var/log/kiwipanel/update.log</code>. You can also view them from the dashboard at <strong>System → Update Logs</strong>.</p><h2 id="api-reference" tabindex="-1">API Reference <a class="header-anchor" href="#api-reference" aria-label="Permalink to &quot;API Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Auth</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/dashboard/update</code></td><td>Admin</td><td>Render the update page</td></tr><tr><td><code>GET</code></td><td><code>/dashboard/update/check</code></td><td>Admin</td><td>Lightweight version check — returns <code>{current, latest, available}</code></td></tr><tr><td><code>GET</code></td><td><code>/dashboard/update/status</code></td><td>Admin</td><td>SSE stream of update progress</td></tr><tr><td><code>POST</code></td><td><code>/dashboard/update/prepare</code></td><td>Admin</td><td>Start update (download + stage) — returns 202 immediately</td></tr><tr><td><code>GET</code></td><td><code>/ping</code></td><td>None</td><td>Health check for restart detection — returns <code>{&quot;status&quot;:&quot;ok&quot;}</code></td></tr></tbody></table><h3 id="cli-commands" tabindex="-1">CLI Commands <a class="header-anchor" href="#cli-commands" aria-label="Permalink to &quot;CLI Commands&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>kiwipanel panel update</code></td><td>Check if an update is available</td></tr><tr><td><code>kiwipanel panel update apply</code></td><td>Apply a staged update (requires root)</td></tr></tbody></table>`,71)])])}const k=e(n,[["render",l]]);export{u as __pageData,k as default};
